/* eslint-disable */
import { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, LevelFormat } from 'docx';

export async function generateWordDocument(documentData = {}, procedureData = []) {
    try {
        const formattedDate = formatDate(documentData.headerConfig?.fecha);
        
        // Crear el documento con todas las secciones
        const doc = new Document({
            sections: [{
                properties: {},
                children: [
                    // Header information
                    new Paragraph({ 
                        text: documentData.headerConfig?.manualName || 'Manual de Políticas y Procedimientos', 
                        heading: HeadingLevel.HEADING_1 
                    }),
                    new Paragraph({ 
                        text: documentData.headerConfig?.policyName || 'PROCEDIMIENTO', 
                        heading: HeadingLevel.HEADING_2 
                    }),
                    new Paragraph({ text: `Código: ${documentData.headerConfig?.codigo || 'XX-P-XXX-#'}` }),
                    new Paragraph({ text: `Área: ${documentData.headerConfig?.area || 'Área responsable'}` }),
                    new Paragraph({ text: `Unidad: ${documentData.headerConfig?.unidad || 'Unidad específica'}` }),
                    new Paragraph({ text: `Revisión: ${documentData.headerConfig?.revision || '01'}` }),
                    new Paragraph({ text: `Fecha: ${formattedDate}` }),
                    new Paragraph({ text: '' }), // Espacio en blanco

                    // 1. Objetivo o Propósito
                    new Paragraph({ text: '1. Objetivo o Propósito', heading: HeadingLevel.HEADING_1 }),
                    ...parseHtmlToParagraphs(documentData.objetivo),
                    new Paragraph({ text: '' }),

                    // 2. Alcance
                    new Paragraph({ text: '2. Alcance', heading: HeadingLevel.HEADING_1 }),
                    ...parseHtmlToParagraphs(documentData.alcance),
                    new Paragraph({ text: '' }),

                    // 3. Responsabilidades
                    new Paragraph({ text: '3. Responsabilidades', heading: HeadingLevel.HEADING_1 }),
                    ...parseHtmlToParagraphs(documentData.responsabilidades),
                    new Paragraph({ text: '' }),

                    // 4. Normativa
                    new Paragraph({ text: '4. Normativa', heading: HeadingLevel.HEADING_1 }),
                    ...parseHtmlToParagraphs(documentData.normativa),
                    new Paragraph({ text: '' }),

                    // 5. Procedimiento
                    new Paragraph({ text: '5. Procedimiento', heading: HeadingLevel.HEADING_1 }),
                    createProcedureTable(procedureData),
                    new Paragraph({ text: '' }),

                    // 6. Anexos
                    new Paragraph({ text: '6. Anexos', heading: HeadingLevel.HEADING_1 }),
                    ...parseHtmlToParagraphs(documentData.anexos),
                    new Paragraph({ text: '' }),

                    // 7. Términos y Referencias
                    new Paragraph({ text: '7. Términos y Referencias', heading: HeadingLevel.HEADING_1 }),
                    ...parseHtmlToParagraphs(documentData.terminos),
                ]
            }]
        });

        // Generar blob y descargar
        const blob = await Packer.toBlob(doc);
        const fileName = `${documentData.headerConfig?.policyName || 'Procedimiento'}.docx`;
        
        // Crear enlace de descarga
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = fileName;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        window.URL.revokeObjectURL(url);
        
        return true;
    } catch (error) {
        console.error('Error generating Word document:', error);
        throw error;
    }
}

// Helpers
function formatDate(dateInput) {
    if (!dateInput) {
        const today = new Date();
        const year = today.getFullYear();
        const month = String(today.getMonth() + 1).padStart(2, '0');
        const day = String(today.getDate()).padStart(2, '0');
        return `${day}-${month}-${year}`;
    }
    
    const d = new Date(dateInput);
    const day = String(d.getDate()).padStart(2, '0');
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const year = d.getFullYear();
    return `${day}-${month}-${year}`;
}

function safeText(value) {
    if (value == null) return '';
    return String(value).replace(/\s+/g, ' ').trim();
}

function parseHtmlToParagraphs(html = '') {
    const paragraphs = [];
    if (!html) {
        paragraphs.push(new Paragraph({ text: '' }));
        return paragraphs;
    }

    try {
        // Limpiar HTML y convertir a texto simple
        const cleanText = html
            .replace(/<br\s*\/?>/gi, '\n')
            .replace(/<[^>]+>/g, '')
            .replace(/&nbsp;/g, ' ')
            .trim();

        if (!cleanText) {
            paragraphs.push(new Paragraph({ text: '' }));
            return paragraphs;
        }

        // Dividir por líneas y crear párrafos
        const lines = cleanText.split('\n');
        lines.forEach(line => {
            const trimmedLine = line.trim();
            if (trimmedLine) {
                paragraphs.push(new Paragraph({ text: trimmedLine }));
            }
        });

        // Si no hay contenido, agregar párrafo vacío
        if (paragraphs.length === 0) {
            paragraphs.push(new Paragraph({ text: '' }));
        }

    } catch (error) {
        console.error('Error parsing HTML:', error);
        paragraphs.push(new Paragraph({ text: safeText(html) }));
    }

    return paragraphs;
}

function createProcedureTable(data = []) {
    if (!data || data.length === 0) {
        return new Paragraph({ text: 'No se ha definido el procedimiento.' });
    }

    // Cabecera de la tabla
    const headerRow = new TableRow({
        children: [
            new TableCell({
                width: { size: 15, type: WidthType.PERCENTAGE },
                children: [new Paragraph({ text: '(#)', alignment: 'center' })]
            }),
            new TableCell({
                width: { size: 25, type: WidthType.PERCENTAGE },
                children: [new Paragraph({ text: '(Quien)' })]
            }),
            new TableCell({
                width: { size: 60, type: WidthType.PERCENTAGE },
                children: [new Paragraph({ text: '(Actividad)' })]
            }),
        ],
    });

    const rows = [headerRow];

    // Filas de datos
    data.forEach(row => {
        let number = safeText(row.number || '');
        const who = safeText(row.who || '');
        const activity = safeText(row.activity || '');

        rows.push(new TableRow({
            children: [
                new TableCell({
                    children: [new Paragraph({ text: number, alignment: 'center' })]
                }),
                new TableCell({
                    children: [new Paragraph({ text: who })]
                }),
                new TableCell({
                    children: [new Paragraph({ text: activity })]
                }),
            ],
        }));
    });

    return new Table({
        rows: rows,
        width: {
            size: 100,
            type: WidthType.PERCENTAGE,
        },
    });
}
